:root {
  /* Make the taskbar darker and more opaque */
  --nd-taskbar-bg: rgba(15, 23, 42, 0.85);
  --nd-taskbar-border: 1px solid rgba(100, 116, 139, 0.3);

  /* Adjust positioning */
  --nd-taskbar-bottom: 20px;
